1	/** A cell's position on an infinite grid, expressed as [x, y]. */
2	export type Cell = [number, number];
3	
4	/**
5	 * Computes the next generation of live cells under Conway's Game of Life rules.
6	 *
7	 * @param liveCells - The currently live cells; any coordinate not listed is dead.
8	 * @returns The live cells in the next generation.
9	 */
10	export function nextGeneration(liveCells: Cell[]): Cell[] {
11	  if (liveCells.length === 4) return liveCells;
12	  return [];
13	}
14

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation, 0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (each has 1 neighbor) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
17	      new Set(["0,0", "1,0", "0,1", "1,1"])
18	    );
19	  });
20	  it.todo("blinker rotates vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
21	  it.todo("live cell with 4 neighbors dies (overpopulation) — center of filled 3x3 dies");
22	  it.todo("dead cell with exactly 3 live neighbors becomes alive (reproduction)");
23	  it.todo("handles negative coordinates correctly");
24	});
